ee:variables.ee:set-variable:
%dw 2.0 output application/json
var maxBodyLength = 2048 var rawBody = write(payload, "application/json") default "" var truncatedBody = if (sizeOf(rawBody) > maxBodyLength) (rawBody[0 to maxBodyLength - 1]) ++ "...[TRUNCATED]" else rawBody
var safeHeaders = attributes.headers default {} filterObject ((value, key) -> !(lower(key as String) contains "authorization") and !(lower(key as String) contains "x-api-key") and !(lower(key as String) contains "cookie") ) --- { level: "INFO", logType: "REQUEST", correlationId: correlationId, timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}, applicationName: app.name, environment: Mule::p('mule.env') default "local", spanId: uuid(), request: { method: attributes.method default "UNKNOWN", path: attributes.requestPath default attributes.requestUri default "unknown", remoteAddress: attributes.remoteAddress default "unknown", headers: safeHeaders, queryParams: attributes.queryParams default {}, body: truncatedBody } }

%dw 2.0 output application/json
var maxBodyLength = 2048 var rawBody = write(payload, "application/json") default "" var truncatedBody = if (sizeOf(rawBody) > maxBodyLength) (rawBody[0 to maxBodyLength - 1]) ++ "...[TRUNCATED]" else rawBody
var startTime = vars.requestStartTime default now() var responseTimeMs = (now() - startTime) as Number {unit: "milliseconds"} default 0 --- { level: "INFO", logType: "RESPONSE", correlationId: correlationId, timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}, applicationName: app.name, environment: Mule::p('mule.env') default "local", spanId: vars.spanId default uuid(), response: { statusCode: vars.httpStatus default 200, responseTimeMs: responseTimeMs, body: truncatedBody } }
